`).map((w,E)=>{if(w==="")return s.jsx("div",{style:{height:8}},E);const N=w.split(/\*\*(.*?)\*\*/g);return s.jsx("p",{style:{fontSize:13.5,lineHeight:1.75,color:"#3a3a3a",marginBottom:2},children:N.map((_,W)=>W%2===1?s.jsx("strong",{style:{color:"#1a1a1a",fontWeight:600},children:_},W):s.jsx("span",{children:_},W))},E)});return s.jsxs("div",{style:{fontFamily:"'Source Serif 4',Georgia,serif",background:"#F5F3EE",minHeight:u?"auto":"100vh",color:"#1a1a1a"},children:[s.jsx("style",{children:`
